SELECT school_name, location, school_type_id, contact_email
FROM schools
WHERE established_year > 2000 AND accreditation_status = 'Gold';

SELECT COUNT(student_id) 
FROM students 
WHERE program_id = (SELECT program_id FROM students WHERE student_name = 'John Doe');

SELECT communication_id, recipient_id, message, date_sent, subject, is_read
FROM communications
WHERE user_id = 1;

SELECT retention_rate, graduation_rate
FROM analytics
WHERE program_id = (
    SELECT program_id
    FROM analytics
    WHERE average_gpa = (
        SELECT MAX(average_gpa)
        FROM analytics
    )
);
